/// `add_to_scheduled_pool()`) and must NOT have their counters decremented on removal.
fn decrement_calldata_counters(&mut self, tx: &Arc<ValidPoolTransaction<T::Transaction>>) {
    let input_len = tx.transaction.input().len();
    self.total_calldata_bytes = self.total_calldata_bytes.saturating_sub(input_len);
    if let Some(sender_bytes) = self.sender_calldata.get_mut(&tx.sender_id()) {
        *sender_bytes = sender_bytes.saturating_sub(input_len);
        if *sender_bytes == 0 {
            self.sender_calldata.remove(&tx.sender_id());
        }
    }
}

