/// Validate executor address and TTL bounds (shared by all async payload validators).
fn validate_executor_and_ttl_bounds(executor: Address, ttl: u64) -> Result<(), AsyncPayloadError> {
    if executor == Address::ZERO {
        return Err(AsyncPayloadError::ExecutorZeroAddress);
    }
    if ttl == 0 {
        return Err(AsyncPayloadError::TTLZero);
    }
    let max_ttl = max_ttl_blocks();
    if ttl > max_ttl {
        return Err(AsyncPayloadError::TTLExceeded { ttl, max: max_ttl });
    }
    Ok(())
}

