/// Try to claim one-time startup hydration ownership.
pub fn try_begin_startup_hydration(&self) -> bool {
    self.last_synced_block
        .compare_exchange(0, STARTUP_HYDRATING_SENTINEL, Ordering::AcqRel, Ordering::Acquire)
        .is_ok()
}

