/// "misconfig cliff": when `scheduled_cap >= total_cap` and `regular_cap > 0`,
/// the allocator's overflow rule forces scheduled to 0). Subsequent calls are no-ops.
fn validate_async_sim_caps_once() {
    use std::sync::OnceLock;
    static WARNED: OnceLock<()> = OnceLock::new();
    if WARNED.set(()).is_err() {
        return;
    }

    let total: usize = std::env::var("RETH_MAX_ASYNC_SIMS_PER_BLOCK")
        .ok()
        .and_then(|s| s.parse().ok())
        .unwrap_or(DEFAULT_MAX_ASYNC_SIMS_PER_BLOCK);
    let sched: usize = std::env::var("RETH_MAX_SCHEDULED_ASYNC_SIMS_PER_BLOCK")
        .ok()

        target: "payload_builder::policy",
        total, sched, reg,
        "Misconfig: RETH_MAX_SCHEDULED_ASYNC_SIMS_PER_BLOCK >= RETH_MAX_ASYNC_SIMS_PER_BLOCK \
         with RETH_MAX_REGULAR_ASYNC_SIMS_PER_BLOCK > 0 — the allocator's regular-priority \
         overflow rule will force the scheduled lane to 0 sims when both lanes have \
         demand. Lower the scheduled cap below the total ceiling, or raise the total."
    );
}
if reg >= total && sched > 0 {
    tracing::warn!(
        target: "payload_builder::policy",
        total, sched, reg,
        "Misconfig: RETH_MAX_REGULAR_ASYNC_SIMS_PER_BLOCK >= RETH_MAX_ASYNC_SIMS_PER_BLOCK \
         with RETH_MAX_SCHEDULED_ASYNC_SIMS_PER_BLOCK > 0 — under the allocator's overflow \
         rule the scheduled lane may receive substantially fewer sim slots than configured."
    );
}
if sched > total {
    tracing::warn!(
        target: "payload_builder::policy",
        total, sched,

}

