/// Covers the cost of spawning a new OpenClaw agent container via claw-spawner.
/// Calibrated to be slightly higher than DKMS due to Docker container overhead.
pub const PERSISTENT_AGENT_EXECUTOR_FEE_WEI: u128 = 10_000_000_000_000; // 0.00001 ETH

